            factory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            // Compile schema from string content
            this.schema = factory.newSchema(
                new javax.xml.transform.stream.StreamSource(
                    new StringReader(schemaContent)
                )
            );

        } catch (SAXException e) {
            throw new Exception("Failed to parse XML Schema: " + e.getMessage(), e);
        } catch (IllegalArgumentException e) {
            throw new Exception("Invalid schema content: " + e.getMessage(), e);
        } catch (Exception e) {
            throw new Exception("Unexpected error loading schema: " + e.getMessage(), e);
        }
    }

    /**
     * Returns the currently loaded schema.
     *
     * @return the loaded Schema object, or null if no schema is loaded
     */
    public Schema getSchema() {
        return this.schema;
    }

    /**
     * Clears the currently loaded schema.
     */
    public void clearSchema() {
        this.schema = null;
    }
}
